mapper.update:
/* SQL ID : TkexamRsltDAO.userListEvlScrBulkModify 설 명 : 사용자목록평가점수일괄수정 */ MERGE INTO TB_LMS_TKEXAM_RSLT TKEXAM_RSLT USING (
SELECT #{item.tkexamRsltId} AS TKEXAM_RSLT_ID , #{item.tkexamId} AS TKEXAM_ID , #{item.userId} AS USER_ID , TO_NUMBER(#{item.scr}) AS TOT_SCR , #{item.scoreType} AS SCORE_TYPE , #{item.rgtrId} AS RGTR_ID FROM DUAL
) USR ON ( TKEXAM_RSLT.TKEXAM_ID = USR.TKEXAM_ID AND TKEXAM_RSLT.USER_ID = USR.USER_ID ) WHEN MATCHED THEN UPDATE SET TKEXAM_RSLT.TOT_SCR = CASE WHEN USR.SCORE_TYPE = 'addition' THEN CASE WHEN NVL(TKEXAM_RSLT.TOT_SCR, 0.0) + USR.TOT_SCR < 0.0 THEN 0.0 WHEN NVL(TKEXAM_RSLT.TOT_SCR, 0.0) + USR.TOT_SCR > 100.0 THEN 100.0 ELSE NVL(TKEXAM_RSLT.TOT_SCR, 0.0) + USR.TOT_SCR END ELSE USR.TOT_SCR END , TKEXAM_RSLT.EVLYN = 'Y' , TKEXAM_RSLT.EVL_DTTM = FN_DTTM() , TKEXAM_RSLT.MDFR_ID = USR.RGTR_ID , TKEXAM_RSLT.MOD_DTTM = FN_DTTM() WHEN NOT MATCHED THEN INSERT ( TKEXAM_RSLT_ID , TKEXAM_ID , USER_ID , TOT_SCR , EVLYN , EVL_DTTM , RGTR_ID , REG_DTTM ) VALUES ( USR.TKEXAM_RSLT_ID , USR.TKEXAM_ID , USR.USER_ID , CASE WHEN USR.TOT_SCR < 0 THEN 0 ELSE USR.TOT_SCR END , 'Y' , FN_DTTM() , USR.RGTR_ID , FN_DTTM() )
